mapper.select:
SELECT MM.TBL_MTRL_M_ID as tblInvProductId, MM.CMPY_CD as cmpyCd, MM.AGNT_CD as agntCd, (SELECT AGNT_NM FROM TBL_AGENCY_M WHERE AGNT_CD = MM.AGNT_CD AND CMPY_CD = MM.CMPY_CD) as agntNm, MM.MTRL_CD as productCd, MM.MTRL_NM as productNm, ISNULL(MM.CURRENT_QUANTITY, 0) as currentQty, MM.SAVE_TIME as saveTime, MM.SAVE_USER as saveUser, MM.UPDT_TIME as updtTime, MM.UPDT_USER as updtUser FROM TBL_MTRL_M MM WHERE 1=1 AND MM.MTO_YN = 'N' -- MTO가 아닌 상품만 조회
AND MM.CMPY_CD = #{cmpyCd}
AND MM.AGNT_CD = #{agntCd}
AND MM.MTRL_CD LIKE '%' + #{productCd} + '%'
AND MM.MTRL_NM LIKE '%' + #{productNm} + '%'
ORDER BY MM.MTRL_CD

mapper.update:
UPDATE TBL_MTRL_M 
SET CURRENT_QUANTITY = #{afterQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = ISNULL(#{saveUser}, 'SYSTEM')
WHERE CMPY_CD = #{cmpyCd}
  AND AGNT_CD = #{agntCd}
  AND MTRL_CD = #{productCd}
  AND MTO_YN = 'N'
